const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let out=[];
for(let t=0;t<T;++t){
  const N=Number(input[idx++]);
  const S=input[idx++];
  let cnt0=0,cnt1=0;
  for(let i=0;i<N;++i){
    if(S[i]==='0') cnt0++; else cnt1++;
  }
  let ok=false;
  if(N%2===1) ok=true;
  else if(cnt0===cnt1) ok=true;
  else if((cnt0%2===0)&&(cnt1%2===0)) ok=true;
  out.push(ok?"YES":"NO");
}
console.log(out.join('\n'));
